sys_script_include.script:
var ContactList = Class.create();

ContactList.CONTACT_MAIN_LIST_BREADCRUMB = [
    ...Constants.HOME_BREADCRUMB,
    { title: "Contacts", link: "?id=contacts" },
];

ContactList.prototype = Object.extendsObject(TableProvider, {
    getRowClickAction: function () {
        return {
            target: "firstColumn",
            action: {
                type: "link",
                urlField: "_primaryLink",
            },
        };
    },

    getContextMenuItems: function (record) {
        return [
            {
                label: "Copy ID",
                iconName: "icon-idcard",
                action: { clipboard: record.user_name || "" },
            },
            {
                label: "Copy URL",
                iconName: "icon-reply-message",
                action: { clipboard: record._primaryLink || "" },
            },
            {
                label: "Open in new tab",
                iconName: "icon-play-filled",
                action: { href: record._primaryLink, target: "_blank" },
            },
        ];
    },

    _initializeConfigObject: function () {
        return {
            table: "sys_user",
            static_query: "active=true",
            show_new_record_button: "true",
            page_title: "Contacts",
            order_by: "user_name",
            order_direction: "ASC",
            limit: "10",
            can_save_preferences: "true",
            fields_preference_name: "scm_portal.contacts.fields",
            order_by_preference_name: "scm_portal.contacts.order_by",
            order_direction_preference_name:
                "scm_portal.contacts.order_direction",
            limit_preference_name: "scm_portal.contacts.limit",
            can_configure_columns: "true",
            detail_view_page: "contact_details",
            /* prettier-ignore-start */
            columns: [
                { label: "User ID", name: "user_name", default: true },
                { label: "First name", name: "first_name", default: true },
                { label: "Last name", name: "last_name", default: true },
                { label: "Email", name: "email", default: true },
                { label: "Business Phone", name: "phone" },
                { label: "Title", name: "title", default: true },
                {
                    label: "Department",
                    name: "department",
                    sourceField: "department.name",
                },
                { label: "Company", name: "company" },
                { label: "Manager", name: "manager" },
            ],
            /* prettier-ignore-end */
            can_filter: "true",
            reference_search_field_map: {
                department: "name",
            },
            id_field: "user_name",
            filter_fields: [
                {
                    field: "department",
                    label: "Department",
                    type: "reference",
                    referenceTable: "cmn_department",
                    referenceSearchField: "name",
                    displayFields: "name;id",
                    displayField: "name",
                    searchFields: "name;id",
                    referenceQualifier: "nameISNOTEMPTY^idISNOTEMPTY",
                    placeholder: "Select a department",
                    pageSize: "10",
                    minimumInputLength: "2",
                    orderBy: "name",
                    orderDirection: "desc",
                },
            ],
            breadcrumbs: ContactList.CONTACT_MAIN_LIST_BREADCRUMB,
        };
    },

    type: "ContactList",
});
